import React, { useState } from 'react'
import { LoginBackGround } from '../assets/img';
import {motion} from 'framer-motion'

export const Login = () => {
  const [imgWidth, setImgWidth] = useState(0);
  const [screenWidth, setScreenWidth] = useState(0);
  return (

    <motion.img src={LoginBackGround} className='w-screen h-aotu'
    // className="absolute w-[200%] h-full)] bg-cover bg-center"
    onLoad={(e) => setImgWidth(e.currentTarget.width)} // 图片加载后更新宽度
    animate={{ x: ["0%", `${screenWidth - imgWidth}px`, "0%"] }}
    transition={{ repeat: Infinity, duration: 10, ease: "linear" }}
    />
    // <div>Login</div>
  )

}

export default Login;
